### accounts Table
```sql
CREATE TABLE accounts (
    id TEXT PRIMARY KEY,              -- UUID
    provider TEXT NOT NULL,           -- claude, codex, gemini
    email TEXT NOT NULL,              -- Account identifier
    label TEXT,                       -- User-defined label
    credential_hash TEXT,             -- Hash of credential content
    added_at TEXT NOT NULL,           -- ISO8601 timestamp
    last_seen_at TEXT,                -- Last activity
    is_active BOOLEAN DEFAULT true,
