/// Check if a CLI binary is available and get its version.
pub async fn check_cli_installed(provider: Provider) -> DiagnosticCheck {
    let cli_name = provider.cli_name();
    let start = Instant::now();

    match which::which(cli_name) {
        Ok(path) => {
            // Try to get version
            let version = get_cli_version(cli_name).await;
            DiagnosticCheck {
                name: format!("{} CLI installed", cli_name),
                status: CheckStatus::Pass {
                    details: Some(format!("Found at {:?}, version: {}", path, version.unwrap_or("unknown".into()))),
                },
                duration: Some(start.elapsed()),
            }
        }
        Err(_) => DiagnosticCheck {
            name: format!("{} CLI installed", cli_name),
            status: CheckStatus::Fail {
                reason: "CLI not found in PATH".into(),
                suggestion: Some(provider.install_suggestion()),
            },
            duration: Some(start.elapsed()),
        },
    }
}

