async fn check_claude_auth() -> DiagnosticCheck {
    let claude_dir = dirs::home_dir().map(|h| h.join(".claude"));

    if let Some(dir) = claude_dir {
        let creds_path = dir.join(".credentials.json");
        if creds_path.exists() {
            // Try to read and validate
            match read_claude_credentials(&creds_path) {
                Ok(creds) => CheckStatus::Pass {
                    details: creds.email.map(|e| format!("Logged in as {}", e)),
                },
                Err(e) => CheckStatus::Fail {
                    reason: format!("Credentials file invalid: {}", e),
                    suggestion: Some("Run: claude auth login".into()),
                },
            }
        } else {
            CheckStatus::Fail {
                reason: "No credentials file found".into(),
                suggestion: Some("Run: claude auth login".into()),
            }
        }
    } else {
        CheckStatus::Fail {
            reason: "Cannot determine home directory".into(),
            suggestion: None,
        }
    }
}
