### Network Detection
```rust
pub struct NetworkChecker;

impl NetworkChecker {
    /// Quick check if network is likely available
    pub async fn is_available(&self) -> bool {
        // Try to reach a reliable endpoint
        let client = reqwest::Client::builder()
            .timeout(Duration::from_secs(2))
            .build()
            .ok();

        if let Some(client) = client {
            // Try multiple endpoints in parallel
            let checks = vec![
                client.head("https://www.google.com").send(),
                client.head("https://api.anthropic.com").send(),
            ];

            let results = futures::future::join_all(checks).await;
            results.iter().any(|r| r.is_ok())
        } else {
            false
        }
    }

    /// Check with minimal latency (for prompt integration)
    pub fn is_likely_available(&self) -> bool {
        // Just check if we have any network interface up
        // This is faster but less reliable
        #[cfg(unix)]
        {
            use std::process::Command;
            Command::new("ping")
                .args(["-c", "1", "-W", "1", "8.8.8.8"])
                .output()
                .map(|o| o.status.success())
                .unwrap_or(false)
        }

        #[cfg(not(unix))]
        true  // Assume available on non-unix
    }
}
